import React, { useEffect, useState } from "react";
import API from "../api/api";

function DriverDashboard() {
  const [trips, setTrips] = useState([]);

  useEffect(() => {
    API.get("/driver/45/trips?date=2025-09-02")
      .then((res) => setTrips(res.data.assigned_trips))
      .catch((err) => console.log(err));
  }, []);

  return (
    <div>
      <h2 className="text-xl font-bold mb-2">Assigned Trips</h2>
      <ul>
        {trips.map((trip) => (
          <li key={trip.trip_id}>
            Trip {trip.trip_id}, Report at: {trip.report_time}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default DriverDashboard;
